Unchecked Func:
pub const unsafe fn unwrap_unchecked(self) -> T {
    match self {
        Some(val) => val,
        // SAFETY: the safety contract must be upheld by the caller.
        None => unsafe { hint::unreachable_unchecked() },
    }
}

Checked Func:
pub const fn unwrap(self) -> T {
    match self {
        Some(val) => val,
        None => unwrap_failed(),
    }
}
